'use client';
import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { usuariosService } from '@/services/usuariosService';
import { useAuth } from '@/hooks/useAuth';

export default function UsuarioPerfilPage() {
  const { id } = useParams();
  const router = useRouter();
  const { user } = useAuth();
  
  const [usuario, setUsuario] = useState(null);
  const [locales, setLocales] = useState([]);
  const [platos, setPlatos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const cargarUsuario = async () => {
      // 👇 VALIDACIÓN IMPORTANTE: Verificar que id existe
      if (!id) {
        console.error('❌ No hay ID en la URL');
        setError('ID de usuario no proporcionado');
        setLoading(false);
        return;
      }

      // Verificar que id es un número válido
      const userId = parseInt(id);
      if (isNaN(userId) || userId <= 0) {
        console.error('❌ ID inválido:', id);
        setError('ID de usuario inválido');
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        console.log('📍 Cargando usuario ID:', userId);
        
        const data = await usuariosService.getUserById(userId);
        console.log('📍 Data recibida:', data);
        
        if (!data || !data.user) {
          setError('Usuario no encontrado');
          setLoading(false);
          return;
        }
        
        setUsuario(data.user);
        setLocales(data.locals || []);
        setPlatos(data.dishes || []);
        
      } catch (err) {
        console.error('📍 Error:', err);
        setError(err.message || 'Error al cargar el perfil');
      } finally {
        setLoading(false);
      }
    };

    cargarUsuario();
  }, [id]);

  // Si hay error, mostrarlo
  if (error) {
    return (
      <div style={{ padding: '2rem', textAlign: 'center' }}>
        <h2 style={{ color: '#b91c1c' }}>Error</h2>
        <p>{error}</p>
        <button 
          onClick={() => router.push('/')}
          style={{
            marginTop: '1rem',
            padding: '0.5rem 1rem',
            background: '#6b21a8',
            color: 'white',
            border: 'none',
            borderRadius: '0.375rem',
            cursor: 'pointer'
          }}
        >
          Volver al inicio
        </button>
      </div>
    );
  }

  if (loading) return <div style={{ padding: '2rem', textAlign: 'center' }}>Cargando perfil...</div>;
  if (!usuario) return <div style={{ padding: '2rem', textAlign: 'center' }}>Usuario no encontrado</div>;

  // Resto del código del perfil...
  return (
    <div style={{ maxWidth: '1280px', margin: '0 auto', padding: '2rem' }}>
      <button onClick={() => router.back()} style={{ marginBottom: '1rem', color: '#6b21a8' }}>
        ← Volver
      </button>

      {/* Header del perfil */}
      <div style={{ background: 'white', borderRadius: '0.75rem', padding: '1.5rem', marginBottom: '2rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
          <div style={{
            width: '5rem',
            height: '5rem',
            background: 'linear-gradient(to right, #9333ea, #db2777)',
            borderRadius: '50%',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'white',
            fontSize: '2rem',
            fontWeight: 'bold'
          }}>
            {(usuario.name || usuario.username || '?').charAt(0).toUpperCase()}
          </div>
          <div>
            <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>{usuario.name || usuario.username}</h1>
            <p style={{ color: '#4b5563' }}>@{usuario.username}</p>
            <p style={{ color: '#6b7280', marginTop: '0.25rem' }}>
              {locales.length} locales • {platos.length} platos
            </p>
          </div>
        </div>

        {/* Botones para crear (solo si es el propio usuario) */}
        {user && user.id == id && (
          <div style={{ marginTop: '1.5rem', display: 'flex', gap: '1rem' }}>
            <button
              onClick={() => router.push('/plato/nuevo')}
              style={{
                background: 'linear-gradient(to right, #9333ea, #db2777)',
                color: 'white',
                padding: '0.5rem 1rem',
                border: 'none',
                borderRadius: '0.375rem',
                cursor: 'pointer'
              }}
            >
              + Nuevo Plato
            </button>
            <button
              onClick={() => router.push('/local/nuevo')}
              style={{
                background: '#10b981',
                color: 'white',
                padding: '0.5rem 1rem',
                border: 'none',
                borderRadius: '0.375rem',
                cursor: 'pointer'
              }}
            >
              + Nuevo Local
            </button>
          </div>
        )}
      </div>

      {/* Tabs y contenido... (el resto igual) */}
    </div>
  );
}